import{_ as e,c as a,a as n,o as i}from"./app-CEcM0piI.js";const t={};function l(d,s){return i(),a("div",null,s[0]||(s[0]=[n(`<p>mustache：vue中的双大括号取值参考了mustache</p><p>对于简单的双大括号内的内容替换可以使用正则的方式替换 但对于数组布尔等复杂的内容值操作就难以处理了 mustache借助了tokens做过渡用以下的流程来实现 ![[Pasted image 20250414170001.png]]</p><h3 id="token" tabindex="-1"><a class="header-anchor" href="#token"><span>token</span></a></h3><p>tokens是一个js的嵌套数组说白了，就是模板字符串的JS表示 它是抽象语法树（AST）、虚拟节点等等的开山鼻祖</p><p>模板字符串</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;h1&gt;我买了一个{{thing}},好{{mood}}啊&lt;/h1&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>转换成的tokens tokens数组中的每个数组都是一个token</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[</span></span>
<span class="line"><span>	[&quot;text&quot; , &quot;&lt;h1&gt;我买了一个&quot;],</span></span>
<span class="line"><span>	[&quot;name&quot; , &quot;thing&quot;],</span></span>
<span class="line"><span>	[&quot;text&quot; , &quot;好&quot;],</span></span>
<span class="line"><span>	[&quot;name&quot; , &quot;mood&quot;],</span></span>
<span class="line"><span>	[&quot;text&quot; , &quot;啊&lt;/h1&gt;&quot;]，</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><strong>当模板字符串中有循环存在时，它将被编译为嵌套更深的tokens</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div&gt;</span></span>
<span class="line"><span>	&lt;ul&gt;</span></span>
<span class="line"><span>		{#arr}}</span></span>
<span class="line"><span>			&lt;li&gt;{{.}}&lt;/li&gt;</span></span>
<span class="line"><span>		{{/arr}}</span></span>
<span class="line"><span>	&lt;/ul&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>[&quot;text&quot;,&quot;&lt;div&gt;&lt;ul&gt;&quot;],</span></span>
<span class="line"><span>	[&quot;#&quot;, &quot;arr&quot;, [</span></span>
<span class="line"><span>		[&quot;text&quot;,&quot;&lt;li&gt;&quot;],</span></span>
<span class="line"><span>		[&quot;name&quot;, &quot;.&quot;],</span></span>
<span class="line"><span>		[&quot;text&quot;, &quot;&lt;/li&gt;&quot;]</span></span>
<span class="line"><span>	]],</span></span>
<span class="line"><span>[&quot;text&quot;,&quot;&lt;/ul&gt;&lt;/div&gt;&quot;]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>如果循环时双重循环，那么tokens会更深一层</p><h1 id="虚拟dom和diff算法" tabindex="-1"><a class="header-anchor" href="#虚拟dom和diff算法"><span>虚拟DOM和diff算法</span></a></h1><p><strong>虚拟dom相比于直接操作dom的优势：</strong> 在插入（或更新）dom时可以先把要插入的dom合并成一个虚拟dom后再更新，这样只需要更新依次，如果直接插入dom，每次插入dom都需要更新。</p><p><strong>编译时和运行时</strong> 为了更好的支持虚拟dom，vue还区分了编译时和运行时</p><ul><li><p>我们需要有一个虚拟DOM，调用渲染方法将虚拟DOM渲染成真实DOM（缺点就是虚拟DOM编写麻烦）</p></li><li><p>专门写个编译时可以将模板编译成虚拟DOM（在构建的时候进行编译性能更高，不需要再运行的时候进行编译，而且vue3在编译中做了很多优化）</p></li><li><p>diff：最小更新算法</p></li><li><p>虚拟DOM：用JavaScript对象描述DOM的层次结构。DOM中的一切属性都在虚拟DOM中有对应的属性 新虚拟DOM和老虚拟DOM进行diff（精细化比较），算出应该如何最小量更新，最后反映到真正的DOM上。</p></li></ul><p>snabbdom是著名的虚拟DOM库，是diff算法的鼻祖，Vue源码借鉴了snabbdom;</p><p><strong>html解析为虚拟dom对象</strong> html</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div class=&quot;box&quot;&gt;</span></span>
<span class="line"><span>	&lt;h3&gt;我是一个标题&lt;/h3&gt;</span></span>
<span class="line"><span>	&lt;ul&gt;</span></span>
<span class="line"><span>		&lt;li&gt;牛奶&lt;/li&gt;</span></span>
<span class="line"><span>		&lt;li&gt;咖啡&lt;/li&gt;</span></span>
<span class="line"><span>		&lt;li&gt;可乐&lt;/li&gt;</span></span>
<span class="line"><span>	&lt;/ul&gt;</span></span>
<span class="line"><span>&lt;/div&gt;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>转换成的虚拟dom</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>{</span></span>
<span class="line"><span>	&quot;seL&quot;:&quot;div&quot;</span></span>
<span class="line"><span>	&quot;data&quot;:{</span></span>
<span class="line"><span>		&quot;class&quot;:{ &quot;box&quot;: true }</span></span>
<span class="line"><span>	},</span></span>
<span class="line"><span>	&quot;children&quot;:[</span></span>
<span class="line"><span>		{</span></span>
<span class="line"><span>			&quot;seL&quot;:&quot;h3&quot;,</span></span>
<span class="line"><span>			&quot;text&quot;：“我是一个标题&quot;</span></span>
<span class="line"><span>		},{</span></span>
<span class="line"><span>			&quot;sel&quot;:&quot;ul&quot;</span></span>
<span class="line"><span>			&quot;data&quot;: {},</span></span>
<span class="line"><span>			&quot;children&quot;:[</span></span>
<span class="line"><span>				{&quot;sel&quot;: &quot;li&quot;,&quot;text&quot;:&quot;牛奶&quot;},</span></span>
<span class="line"><span>				{&quot;seL&quot;: &quot;li&quot;,&quot;text&quot;:&quot;咖啡&quot;},</span></span>
<span class="line"><span>				{&quot;sel&quot;：&quot;li&quot;,&quot;text&quot;:&quot;可乐&quot;}</span></span>
<span class="line"><span>			]</span></span>
<span class="line"><span>		}</span></span>
<span class="line"><span>	]	</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h3 id="h函数" tabindex="-1"><a class="header-anchor" href="#h函数"><span>h函数</span></a></h3><p>h函数用于产生虚拟节点，命名无其他含义只是snabbdom作者命名</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>//真正的dom节点</span></span>
<span class="line"><span>&lt;a href=&quot;http://www.atguigu.com&quot;&gt;尚硅谷&lt;/a&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//调用h函数</span></span>
<span class="line"><span>h(&#39;a&#39;,{ props:{ href:&#39;http://www.atguigu.com&#39; }},&#39;尚硅谷&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>//h函数返回的虚拟节点</span></span>
<span class="line"><span>{</span></span>
<span class="line"><span>	&quot;sel&quot;:&quot;a&quot;,</span></span>
<span class="line"><span>	&quot;data&quot;:{</span></span>
<span class="line"><span>		props:{ href:&#39;http://www.atguigu.com&#39; }</span></span>
<span class="line"><span>	},</span></span>
<span class="line"><span>	&quot;text&quot;:&quot;尚硅谷&quot;,</span></span>
<span class="line"><span>	&quot;children&quot;:undefined,</span></span>
<span class="line"><span>	&quot;elm&quot;:undefined,</span></span>
<span class="line"><span>	&quot;key&quot;:undefined</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>虚拟节点中的属性</p><ul><li>sel：选择器</li><li>data：标签的属性，样式等</li><li>text：标签中的内容</li><li>children：标签中的子标签</li><li>elm：该虚拟dom对应的真实dom节点，如果是undefined表示还没有上树</li><li>key：该节点的唯一标识</li></ul><p>snabbdom中的patch函数添加dom元素就使用了diff算法 当页面原有dom存在时，使用patch添加新的dom元素会检测，如果部分数据按一样：如开头的顺序，sel，text等就会认为它们是一样的就不会更新，只更新内容不一样的 如果开头的顺序也不一样那么就会全部更新（也就是vue中的v-for的特性） 为虚拟dom添加key属性（也就是vue中的:key操作）就会给diff算法提供了唯一标识，告诉diff算法，在更改前后它们是同一个DOM节点。这样可以不按顺序也能触发diff</p><ul><li>只有是同一个虚拟节点，才进行精细化比较否则就是暴力删除旧的、插入新的。 同一个虚拟节点的判定：选择器相同且key相同。</li><li>只进行同层比较，不会进行跨层比较。即使是同一片虚拟节点，但是跨层了，diff也是暴力删除旧的、然后插入新的</li></ul><h1 id="数据响应式" tabindex="-1"><a class="header-anchor" href="#数据响应式"><span>数据响应式</span></a></h1><p>响应式：数据改变视图也跟随改变</p><h3 id="defineproperty" tabindex="-1"><a class="header-anchor" href="#defineproperty"><span>defineProperty</span></a></h3><p>在js中一个对象可以进行任意操作而没有限制 使用属性描述符能够限制自定义类属性的权限 <strong>获取属性描述符</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Object.getOwnPropertyDescriptor(对象,属性名字符串)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>相当于</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>对象.属性名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>但是得到的不仅有属性的值，还有属性的权限</p><p><strong>设置属性描述符</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Object.defineProperty(对象,属性名字符串,{</span></span>
<span class="line"><span>	value:属性值,</span></span>
<span class="line"><span>	writable:false,      //是否可重写</span></span>
<span class="line"><span>	enmuerable:false,    //是否可遍历</span></span>
<span class="line"><span>	configuration:false, //是否可修改</span></span>
<span class="line"><span>	get:function(){},    //读取器</span></span>
<span class="line"><span>	set:function(){}     //配置器</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>相当于给对象设置属性并赋值，不过可以设置三个权限 读取器和配置器相当于计算属性</p><p><strong>一个属性有了getter和setter函数后就无法使用value赋值了。要正常的获得属性的初始值需要在外部设置一个变量并使用getter和setter函数代理处理，这样通常不安全，通常设置出闭包环境使用</strong></p><p><strong>冻结对象</strong></p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>Object.freeze(对象)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>可以写在类内部冻结类的属性，这样就无法对类的属性进行任何更改了 也可以写在类的外部冻结某个对象，这样就无法对这个对象添加属性了</p><h1 id="ast抽象语法树" tabindex="-1"><a class="header-anchor" href="#ast抽象语法树"><span>AST抽象语法树</span></a></h1><p>Abstract Syntax Tree ![[Pasted image 20250416124400.png]] ![[Pasted image 20250416124726.png]] ast就是解析html字符串 采用栈的方式，遇到开始标签就添加到标签栈中，并在内容栈中添加一个空数组，当遇到文本内容时将内容放到内容栈顶第一个数组中，当遇到结尾标签就将标签栈和内容栈都出栈</p><h1 id="api" tabindex="-1"><a class="header-anchor" href="#api"><span>api</span></a></h1><table><thead><tr><th>类/函数</th><th>作用</th></tr></thead><tbody><tr><td>Function(code)</td><td>接收一个字符串，并将该字符串作为代码执行</td></tr><tr><td>with(obj)</td><td>由于Function中参数的指向不确定，因此需要配合with函数使用。with函数接收一个对象并返回一个字符串，返回的字符串是要以代码执行的内容，接收的对象是给返回值执行时参数指定指向对象，这样返回值执行的函数中的参数都指向了传入的对象</td></tr></tbody></table><h1 id="spa" tabindex="-1"><a class="header-anchor" href="#spa"><span>SPA</span></a></h1><ul><li>SPA（single-page application）单页应用，默认情况下我们编写Vue、React都只有一个html页面，并且提供一个挂载点，最终打包后会再此页面中引入对应的资源。（页面的渲染全部是由JS动态进行渲染的）。切换页面时通过监听路由变化，渲染对应的页面ClientSideRendering，客户端渲染CSR</li><li>MPA（Multi-page application）多页应用，多个html页面。每个页面必须重复加载，js，css等相关资源。（服务端返回完整的html，同时数据也可以再后端进行获取一并返回&quot;模板引擎&quot;）。多页应用跳转需要整页资源刷新。ServerSideRendering，服务器端渲染SSR</li></ul><p><strong>优缺点</strong></p><table><thead><tr><th></th><th>单页面应用(SPA)</th><th>多页面应用（MPA)</th></tr></thead><tbody><tr><td>组成</td><td>一个主页面和页面组件</td><td>多个完整的页面</td></tr><tr><td>刷新方式</td><td>局部刷新</td><td>整页刷新</td></tr><tr><td>SEO搜索引擎优化</td><td>无法实现</td><td>容易实现</td></tr><tr><td>页面切换</td><td>速度快，用户体验良好</td><td>切换加载资源，速度慢，用户体验差</td></tr><tr><td>维护成本</td><td>相对容易</td><td>相对复杂</td></tr></tbody></table><ul><li>用户体验好、快，内容的改变不需要重新加载整个页面，服务端压力小。</li><li>SPA应用不利于搜索引|擎的抓取。</li><li>首次渲染速度相对较慢（第一次返回空的html，需要再次请求首屏数据）白屏时间长。</li></ul><p><strong>解决方法</strong></p><ul><li>静态页面预渲染(StaticSiteGeneration)SSG，在构建时生成完整的html页面。（就是在打包的时候）先将页面放到浏览器中运行一下，将HTML保存起来），仅适合静态页面网站。变化率不高的网站</li><li>SSR+CSR的方式，首屏采用服务端渲染的方式，后续交互采用客户端渲染方式。（NuxtJS）</li></ul><h1 id="虚拟dom" tabindex="-1"><a class="header-anchor" href="#虚拟dom"><span>虚拟DOM</span></a></h1><ul><li>VirtualDOM就是用js对象来描述真实DOM，是对真实DOM的抽象，由于直接操作DOM性能低但是js层的操作效率高，可以将DOM操作转化成对象操作，最终通过diff算法比对差异进行更新DOM（减少了对真实DOM的操作）。</li><li>虚拟DOM不依赖真实平台环境从而也可以实现跨平台。</li></ul><h4 id="vdom的生成过程" tabindex="-1"><a class="header-anchor" href="#vdom的生成过程"><span>VDOM的生成过程</span></a></h4><ol><li>在vue中我们常常会为组件编写模板-template</li><li>这个模板会被编译器编译为渲染函数-render</li><li>在接下来的挂载过程中会调用render函数，返回的对象就是虚拟dom</li><li>会在后续的patch过程中进一步转化为真实dom。</li></ol><h4 id="vdom是如何做diff算法的" tabindex="-1"><a class="header-anchor" href="#vdom是如何做diff算法的"><span>VDOM是如何做diff算法的</span></a></h4><ol><li>挂载过程结束后，会记录第一次生成的VDOM-oldVnode</li><li>当响应式数据发生变化时，将会引|起组件重新render，此时就会生成新的VDOM-newVnode</li><li>使用oldVnode与newVnode做diff操作，将更改的部分应到真实DOM上，从而转换为最小量的dom操作，高效更新视图。</li></ol><h1 id="数据响应式-1" tabindex="-1"><a class="header-anchor" href="#数据响应式-1"><span>数据响应式</span></a></h1><h3 id="vue2的缺陷" tabindex="-1"><a class="header-anchor" href="#vue2的缺陷"><span>vue2的缺陷</span></a></h3><ul><li>在Vue2的时候使用defineProperty来进行数据的劫持，需要对属性进行重写添加getter及setter性能差。</li><li>当新增属性和删除属性时无法监控变化。需要通过<code>$set</code>、<code>$delete</code>实现</li><li>数组不采用defineProperty来进行劫持（浪费性能，对所有索引进行劫持会造成性能浪费）需要对数组单独进行处理。</li><li>对于ES6中新产生的Map、Set这些数据结构不支持。</li></ul><p>数组因为考虑性能的原因并没有使用defineProperty对数组的每一项进行拦截，而是重写数组中的函数。数组中如果是对象数据类型也会递归劫持</p><h3 id="vue3" tabindex="-1"><a class="header-anchor" href="#vue3"><span>vue3</span></a></h3><p>vue3中数据响应式是使用proxy实现的，为对象的每个属性都设置一个代理，当获取和修改属性时由代理接管。也就不用重写get和set函数了</p><h1 id="依赖收集" tabindex="-1"><a class="header-anchor" href="#依赖收集"><span>依赖收集</span></a></h1><ul><li>每个属性都拥有自己的dep属性，存放他所依赖的watcher，当属性变化后会通知自己对应的watcher去更新（当组件挂载时$mount函数会添加watcher）</li><li>默认在初始化时会调用render函数，此时会触发属性依赖收集dep.depend</li><li>当属性发生修改时会触发watcher更新dep.notify()</li></ul><p>![[Pasted image 20250511202803.png]]</p><h4 id="vue3的依赖收集" tabindex="-1"><a class="header-anchor" href="#vue3的依赖收集"><span>vue3的依赖收集</span></a></h4><ul><li>vue3中会通过Map结构将属性和effect映射起来。</li><li>默认在初始化时会调用render函数，此时会触发属性依赖收集track，</li><li>当属性发生修改时会找到对应的effect列表依次执行trigger</li></ul><h1 id="v-show的实现" tabindex="-1"><a class="header-anchor" href="#v-show的实现"><span>v-show的实现</span></a></h1><p>控制dom元素的显示的方法有三种：display、opacity、visvibility v-show的实现使用的时display，原因如下：</p><ol><li>opacity：控制dom元素的透明度，即使透明度为0也会响应元素的各种事件</li><li>visvibility：是占位的，并不能响应元素的事件（即使显示了出来）</li></ol><p>v-show判断元素如果显示时会使用元素本身的display属性，当元素不显示时会修改元素的display属性为none</p><p>v-if会阻断内部代码的执行，优先级比v-show高</p><h1 id="computed和watch的区别" tabindex="-1"><a class="header-anchor" href="#computed和watch的区别"><span>computed和watch的区别</span></a></h1><p>Vue2中有三种watcher（渲染watcher、计算属性watcher、用户watcher） Vue3中有三种effect（渲染effect、计算属性effect、用户effect）</p><p>二者都是基于watcher实现的，computed基于watcher实现了缓存，watch基于watcher实现了api监控数据，数据改变时触发回调</p><p><strong>computed</strong></p><ul><li>计算属性仅当用户取值时才会执行对应的方法。</li><li>computed属性是具备缓存的，依赖的值不发生变化，对其取值时计算属性方法不会重新执行。</li><li>计算属性可以简化模板中复杂表达式。</li><li>计算属性中不支持异步逻辑。</li><li>computed属性是可以在模板中使用的。</li><li>必须有返回值</li></ul><p>每一个计算属性内部维护一个dirty属性dirty：true 当取值的时候dirty为true就执行用户的方法，拿到值缓存起来this.value并且将dirty=false 再次取值的时候dirty为false，直接返回缓存的this.value 当修改了数据时将dirty的值变为true，并且会触发更新，页面重新渲染，重新获取最新计算属性的值</p><ol><li>计算属性会创建一个计算属性watcher，这个watcher（lazy：true）不会立刻执行</li><li>通过object.defineProperty将计算属性定义到实例上</li><li>当用户取值时会触发getter，拿到计算属性对应的watcher，看dirty是否为true，如果为true则求值</li><li>并且让计算属性watcher中依赖的属性收集最外层的渲染watcher，可以做到依赖的属性变化了，触发计算属性更新dirty并且可以触发页面更新</li><li>如果依赖的值没有发生变化，则采用缓存</li></ol><p><strong>watch</strong> watch则是监控值的变化，当值发生变化时调用对应的回调函数。经常用于监控某个值的变化，进行一些操作。（异步要注意竞态问题）</p><h1 id="watch和watcheffect的区别" tabindex="-1"><a class="header-anchor" href="#watch和watcheffect的区别"><span>watch和watchEffect的区别</span></a></h1><ul><li>watchEffect立即运行一个函数，然后被动地追踪它的依赖，当这些依赖改变时重新执行该函数。</li><li>watch侦测一个或多个响应式数据源并在数据源变化时调用一个回调函数。</li></ul><p>二者本质上都是基于ReactiveEffect实现的，差异并不大。watch在于数据变了允许用户对新旧数据进行处理，watchEffect在于数据改变时重新执行函数中的逻辑</p><h1 id="ref和reactive的区别" tabindex="-1"><a class="header-anchor" href="#ref和reactive的区别"><span>ref和reactive的区别</span></a></h1><ul><li>reactive用于处理对象类型的数据响应式。底层采用的是Proxy</li><li>ref通常用于处理单值的响应式，ref主要解决原始值的响应式问题。底层采用的是Object.defineProperty实现的。</li></ul><p>由于reactive是基于proxy实现的，因此它无法处理基础数据类型，这时就只能使用ref了</p><h1 id="new-vue的过程" tabindex="-1"><a class="header-anchor" href="#new-vue的过程"><span>new Vue的过程</span></a></h1><ol><li>在newVue的时候内部会进行初始化操作。</li><li>内部会初始化组件绑定的事件，初始化组件的父子关系<code>$parent</code>、<code>$children</code>、<code>root</code></li><li>初始化响应式数据data、computed、props、watch、method。同时也初始化了provide和inject方法。内部会对数据进行劫持对象采用defineProperty数组采用方法重写。</li><li>再看一下用户是否传入了el属性和template或者render。render的优先级更高，如果用户写的是template，会做模板编译（三部曲）。最终就拿到了render函数</li><li>内部挂载的时候会产生一个watcher，会调用render函数会触发依赖收集。内部还会给所有的响应式数据增加dep属性，让属性记录当前的watcher（用户后续修改的时候可以触发watcher重新渲染）</li><li>vue更新的时候采用虚拟DOM的方式进行diff算法更新。 ![[Pasted image 20250511220117.png]]</li></ol><h1 id="v-if和v-for优先级" tabindex="-1"><a class="header-anchor" href="#v-if和v-for优先级"><span>v-if和v-for优先级</span></a></h1><p>在vue2中v-for和v-if避免在同一个标签中使用，如果遇到需要同时使用时可以考虑写成计算属性的方式。 如果直接将v-if和v-for写在一起会报错，但是将v-if中的判断条件替换成计算属性后就不会报错了</p><ul><li>在Vue2中解析时，先解析v-for在解析v-if。会导致先循环后在对每一项进行判断，浪费性能。</li><li>在Vue3中v-if的优先级高于v-for。（会将v-if提到外层多加一个template标签）</li></ul><h1 id="生命周期" tabindex="-1"><a class="header-anchor" href="#生命周期"><span>生命周期</span></a></h1><table><thead><tr><th>生命周期v2</th><th>生命周期v3</th><th>描述</th></tr></thead><tbody><tr><td>beforeCreate</td><td>beforeCreate</td><td>组件实例被创建之初</td></tr><tr><td>created</td><td>created</td><td>组件实例已经完全创建</td></tr><tr><td>beforeMount</td><td>beforeMount</td><td>组件挂载之前</td></tr><tr><td>mounted</td><td>mounted</td><td>组件挂载到实例上去之后</td></tr><tr><td>beforeUpdate</td><td>beforeUpdate</td><td>组件数据发生变化，更新之前</td></tr><tr><td>updated</td><td>updated</td><td>数据数据更新之后</td></tr><tr><td>beforeDestroy</td><td><strong>beforeUnmount</strong></td><td>组件实例销毁之前</td></tr><tr><td>destroyed</td><td><strong>unmounted</strong></td><td>组件实例销毁之后</td></tr><tr><td>activated</td><td>activated</td><td>keep-alive缓存的组件激活时</td></tr><tr><td>deactivated</td><td>deactivated</td><td>keep-alive缓存的组件停用时调用</td></tr><tr><td>errorCaptured</td><td>errorCaptured</td><td>捕获一个来自子孙组件的错误时被调用</td></tr><tr><td>-</td><td><strong>renderTracked Dev</strong></td><td>调试钩子，响应式依赖被收集时调用</td></tr><tr><td>-</td><td><strong>renderTriggered Dev</strong></td><td>调试钩子，响应式依赖被触发时调用</td></tr><tr><td>-</td><td><strong>serverPrefetch</strong></td><td>ssr only，组件实例在服务器上被渲染前调用</td></tr><tr><td>Vue3中新增了：组合式APl：生命周期钩子，但是不存在onBeforeCreate和onCreated钩子</td><td></td><td></td></tr></tbody></table><h1 id="vue-use" tabindex="-1"><a class="header-anchor" href="#vue-use"><span>Vue.use</span></a></h1><p>安装Vuejs 插件。如果插件是一个对象，必须提供install方法。如果插件是一个函数，它会被作为instal方法。install方法调用时，会将Vue作为参数传入，这样插件中就不再需要依赖Vue了。</p><p>插件通过use函数可以：</p><ul><li>添加全局指令、全局过滤器、全局组件等</li><li>通过全局混入来添加一些组件选项。</li><li>添加Vue实例方法，通过把它们添加到Vue.prototype上实现。</li></ul><h1 id="组件的data为什么必须是个函数" tabindex="-1"><a class="header-anchor" href="#组件的data为什么必须是个函数"><span>组件的data为什么必须是个函数</span></a></h1><ul><li>根实例对象data可以是对象也可以是函数&quot;单例”，不会产生数据污染情况</li><li>组件实例对象data必须为函数，目的是为了防止多个组件实例对象之间共用一个data，产生数据污染。所以需要通过工厂函数返回全新的data作为组件的数据源</li></ul><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>function Vue() {}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Vue.extend = function (options) {</span></span>
<span class="line"><span>	function Sub() {</span></span>
<span class="line"><span>		//会将data存起来</span></span>
<span class="line"><span>		this.data = this.constructor.options.data;</span></span>
<span class="line"><span>	}</span></span>
<span class="line"><span>	Sub.options = options;</span></span>
<span class="line"><span>	return Sub;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>let child = Vue.extend({</span></span>
<span class="line"><span>	data: { name:&quot;xxx&quot;f.</span></span>
<span class="line"><span>})</span></span>
<span class="line"><span>/／两个组件就是两个实例，希望数据互不干扰</span></span>
<span class="line"><span>let childl = new child();</span></span>
<span class="line"><span>let child2 = new Child();</span></span>
<span class="line"><span></span></span>
<span class="line"><span>console.log(child1.data.name) ;</span></span>
<span class="line"><span>childl.data.name = &quot;jw&quot;;</span></span>
<span class="line"><span>console.log(child2.data.name);</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><p>当data是一个对象时，会将对象挂载到当前组件的实例上 调用函数初始化数据时如果多次初始化，后续的实例将会覆盖旧的数据，但它们的data指向的却是同一个对象，在修改一个实例的数据时其他的实例数据也会被修改（浅拷贝） 如果使用data返回值的方式时，每次初始化实例都会返回新的数据，多个实例间数据就被隔离了</p><p>而跟实例是单例的，所以不涉及共享问题也就可以不限于函数或者对象</p><h1 id="函数式组件" tabindex="-1"><a class="header-anchor" href="#函数式组件"><span>函数式组件</span></a></h1><p>函数式组件的特性：无状态、无生命周期、无this，但是性能高。正常组件是一个类继承了Vue，函数式组件就是普通的函数，没有new的过程。最终就是将返回的虚拟DOM变成真实DOM替换对应的组件。</p><p>定义函数式组件：</p><ol><li>在vue2中创建组件时将functional设置为true</li><li>将vue文件中的template标签后加上functional属性</li></ol><blockquote><p>[!NOTE] Title 函数式组件不会被记录在组件的父子关系中，在Vue3中因为所有的组件都不用new了，所以在性能上没有了优势。</p></blockquote><h1 id="v-once" tabindex="-1"><a class="header-anchor" href="#v-once"><span>v-once</span></a></h1><p>v-once是Vue中内置指令，只渲染元素和组件一次。 被v-once指令标记的组件（包括其内部的子组件）只会在创建时渲染依次，随后的重新渲染，元素/组件及其所有的子节点将被视为静态内容并跳过。这可以用于优化更新性能。</p><p>实现原理是缓存，第一次创建被v-once标记的组件时会将其放入到缓存中，下次再获取组件时直接从缓存中获取</p><h3 id="v-memo" tabindex="-1"><a class="header-anchor" href="#v-memo"><span>v-memo</span></a></h3><p>如果希望v-once中部分属性更新了也渲染可以使用v-memo</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>&lt;div v-memo=&#39;[value1,value2]&#39;</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>使用v-memo指定依赖列表中的数据，列表中的任一数据更改都会引起v-memo标记的组件的重渲染</p><p>在vue3.2后新增了一个v-memo指令通过依赖列表的方式控制页面渲染 很像计算属性</p><h1 id="sync" tabindex="-1"><a class="header-anchor" href="#sync"><span>.sync</span></a></h1><p>在vue2中v-model无法绑定多个属性，如果需要绑定多个数据需要使用.sync修饰符 在vue3中v-model可以绑定多个属性</p><h1 id="nexttick" tabindex="-1"><a class="header-anchor" href="#nexttick"><span>nextTick</span></a></h1><p>下次DOM更新循环结束后执行延迟的回调，在修改数据后，立即执行该方法获取更新后的DOM nextTick（）回调函数延迟执行下一次DOM更新后</p><ul><li>Vue中视图更新是异步的，使用nextTick方法可以保证用户定义的逻辑在更新之后执行。</li><li>可用于获取更新后的DOM，多次调用nextTick会被合并。</li></ul><h1 id="keep-alive" tabindex="-1"><a class="header-anchor" href="#keep-alive"><span>keep-alive</span></a></h1><p>keep-alive是vue中的内置组件，能在组件切换过程会缓存组件的实例，而不是销毁它们。在组件再次重新激活时可以通过缓存的实例拿到之前染的DOM进行渲染，无需重新生成节点。</p><h1 id="自定义指令" tabindex="-1"><a class="header-anchor" href="#自定义指令"><span>自定义指令</span></a></h1><p>Vue除了内置指令之外，同时Vue也允许用户注册自定义指令来对Vue进行扩展。指令的目的在于可以<strong>将操作DOM的逻辑进行复用</strong>。</p><ul><li>bind：只调用一次，指令第一次绑定到元素时调用。在这里可以进行一次性的初始化设置。</li><li>inserted：被绑定元素插入父节点时调用(仅保证父节点存在，但不一定已被插入文档中)。</li><li>update：所在组件的VNode更新时调用，但是可能发生在其子VNode更新之前。指令的值可能发生了改变，也可能没有。</li><li>componentUpdated：指令所在组件的VNode及其子VNode全部更新后调用。</li><li>unbind：只调用一次，指令与元素解绑时调用。</li></ul><h1 id="为什么vue2中vue实例是一个函数而不是类" tabindex="-1"><a class="header-anchor" href="#为什么vue2中vue实例是一个函数而不是类"><span>为什么vue2中vue实例是一个函数而不是类</span></a></h1><p>mixins或这其他的公共方法都是vue.prototype上的方法</p>`,131)]))}const r=e(t,[["render",l]]),c=JSON.parse('{"path":"/front/principle/3/","title":"3. vue原理","lang":"zh-CN","frontmatter":{"title":"3. vue原理","createTime":"2025/06/18 21:15:10","permalink":"/front/principle/3/"},"readingTime":{"minutes":18.67,"words":5600},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/原理/3. vue原理.md","headers":[]}');export{r as comp,c as data};
